    pub fn handle_order_book_message(&self, mut client: Value, mut message: Value) {
        // spot markets
        //
        //     {
        //         "ch": "market.btcusdt.mbp.150",
        //         "ts": 1583472025885,
        //         "tick": {
        //             "seqNum": 104998984994,
        //             "prevSeqNum": 104998984977,
        //             "bids": [
        //                 [9058.27, 0],
        //                 [9058.43, 0],
        //                 [9058.99, 0],
        //             ],
        //             "asks": [
        //                 [9084.27, 0.2],
        //                 [9085.69, 0],
        //                 [9085.81, 0],
        //             ]
        //         }
        //     }
        //
        // non-spot market update
        //
        //     {
        //         "ch":"market.BTC220218.depth.size_150.high_freq",
        //         "tick":{
        //             "asks":[],
        //             "bids":[
        //                 [43445.74,1],
        //                 [43444.48,0 ],
        //                 [40593.92,9]
        //             ],
        //             "ch":"market.BTC220218.depth.size_150.high_freq",
        //             "event":"update",
        //             "id":152727500274,
        //             "mrid":152727500274,
        //             "ts":1645023376098,
        //             "version":37536690
        //         },
        //         "ts":1645023376098
        //     }
        // non-spot market snapshot
        //
        //     {
        //         "ch":"market.BTC220218.depth.size_150.high_freq",
        //         "tick":{
        //             "asks":[
        //                 [43445.74,1],
        //                 [43444.48,0 ],
        //                 [40593.92,9]
        //             ],
        //             "bids":[
        //                 [43445.74,1],
        //                 [43444.48,0 ],
        //                 [40593.92,9]
        //             ],
        //             "ch":"market.BTC220218.depth.size_150.high_freq",
        //             "event":"snapshot",
        //             "id":152727500274,
        //             "mrid":152727500274,
        //             "ts":1645023376098,
        //             "version":37536690
        //         },
        //         "ts":1645023376098
        //     }
        //
        let mut ch: Value = self.safe_value_k(message.clone(), "ch", &[]);
        let mut parts: Value = split(&ch, &Value::Str(".".to_string()));
        let mut marketId: Value = self.safe_string(parts.clone(), Value::Int(1), &[]);
        let mut market: Value = self.safe_market(&[marketId.clone()]);
        let mut symbol: Value = get_value(&market, &Value::Str("symbol".to_string()));
        let mut orderbook: Value = get_value(&self.orderbooks, &symbol);
        let mut tick: Value = self.safe_value_k(message.clone(), "tick", &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut seqNum: Value = self.safe_integer_k(tick.clone(), "seqNum", &[]);
        let mut prevSeqNum: Value = self.safe_integer_k(tick.clone(), "prevSeqNum", &[]);
        let mut event: Value = self.safe_string_k(tick.clone(), "event", &[]);
        let mut version: Value = self.safe_integer_k(tick.clone(), "version", &[]);
        let mut timestamp: Value = self.safe_integer_k(message.clone(), "ts", &[]);
        if is_equal(&event, &Value::Str("snapshot".to_string())) {
            let mut snapshot: Value = self.parse_order_book(tick.clone(), symbol.clone(), &[timestamp.clone()]);
            orderbook.reset(snapshot.clone());
            add_element_to_object(&mut orderbook, &Value::Str("nonce".to_string()), version.clone());
        }
        if is_true(&(!is_equal(&prevSeqNum, &Value::Null))) && is_greater_than(&prevSeqNum, &get_value(&orderbook, &Value::Str("nonce".to_string()))) {
            let mut checksum: Value = self.handle_option(Value::Str("watchOrderBook".to_string()), Value::Str("checksum".to_string()), &[Value::Bool(true)]);
            if is_true(&checksum) {
                panic!("{}", crate::exchange_errors::checksum_error(add(&add(&self.id, &Value::Str(" ".to_string())), &self.orderbook_checksum_message(symbol.clone()))));
            }
        }
        let mut spotConditon: Value = Value::Bool(is_true(&get_value(&market, &Value::Str("spot".to_string()))) && is_true(&(is_equal(&prevSeqNum, &get_value(&orderbook, &Value::Str("nonce".to_string()))))));
        let mut nonSpotCondition: Value = Value::Bool(is_true(&get_value(&market, &Value::Str("contract".to_string()))) && is_true(&(is_equal(&subtract(&version, &Value::Int(1)), &get_value(&orderbook, &Value::Str("nonce".to_string()))))));
        if is_true(&spotConditon) || is_true(&nonSpotCondition) {
            let mut asks: Value = self.safe_value_k(tick.clone(), "asks", &[Value::List(vec![])]);
            let mut bids: Value = self.safe_value_k(tick.clone(), "bids", &[Value::List(vec![])]);
            self.handle_deltas(get_value(&orderbook, &Value::Str("asks".to_string())), asks.clone());
            self.handle_deltas(get_value(&orderbook, &Value::Str("bids".to_string())), bids.clone());
            add_element_to_object(&mut orderbook, &Value::Str("nonce".to_string()), ternary(is_true(&spotConditon), seqNum.clone(), version.clone()));
            add_element_to_object(&mut orderbook, &Value::Str("timestamp".to_string()), timestamp.clone());
            add_element_to_object(&mut orderbook, &Value::Str("datetime".to_string()), self.iso8601(timestamp.clone()));
        }
}

