    pub fn parse_order_trade(&mut self, mut trade: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        // spot private wrapped trade
        //
        //     {
        //         "tradePrice": "130.01",
        //         "tradeVolume": "0.0385",
        //         "tradeTime": 1648714741525,
        //         "aggressor": true,
        //         "execAmt": "0.0385",
        //         "orderSource": "spot-web",
        //         "orderSize": "0.0385",
        //         "remainAmt": "0",
        //         "tradeId": 101541578884,
        //         "symbol": "ltcusdt",
        //         "type": "sell-market",
        //         "eventType": "trade",
        //         "clientOrderId": '',
        //         "orderStatus": "filled",
        //         "orderId": 509835753860328
        //     }
        //
        market = self.safe_market(&[Value::Null, market.clone()]);
        let mut symbol: Value = get_value(&market, &Value::Str("symbol".to_string()));
        let mut tradeId: Value = self.safe_string_k(trade.clone(), "tradeId", &[]);
        let mut price: Value = self.safe_string_k(trade.clone(), "tradePrice", &[]);
        let mut amount: Value = self.safe_string_k(trade.clone(), "tradeVolume", &[]);
        let mut order: Value = self.safe_string_k(trade.clone(), "orderId", &[]);
        let mut timestamp: Value = self.safe_integer_k(trade.clone(), "tradeTime", &[]);
        let mut type_var: Value = self.safe_string_k(trade.clone(), "type", &[]);
        let mut side: Value = Value::Null;
        if !is_equal(&type_var, &Value::Null) {
            let mut typeParts: Value = split(&type_var, &Value::Str("-".to_string()));
            side = get_value(&typeParts, &Value::Int(0));
            type_var = get_value(&typeParts, &Value::Int(1));
        }
        let mut aggressor: Value = self.safe_value_k(trade.clone(), "aggressor", &[]);
        let mut takerOrMaker: Value = Value::Null;
        if !is_equal(&aggressor, &Value::Null) {
            takerOrMaker = ternary(is_true(&aggressor), Value::Str("taker".to_string()), Value::Str("maker".to_string()));
        }
        return self.safe_trade(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), trade.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("id".to_string(), tradeId.clone());
        m.insert("order".to_string(), order.clone());
        m.insert("type".to_string(), type_var.clone());
        m.insert("takerOrMaker".to_string(), takerOrMaker.clone());
        m.insert("side".to_string(), side.clone());
        m.insert("price".to_string(), price.clone());
        m.insert("amount".to_string(), amount.clone());
        m.insert("cost".to_string(), Value::Null);
        m.insert("fee".to_string(), Value::Null);
    m
}), &[market.clone()]);

    Value::Null
}

