    pub fn handle_subscription_status(&mut self, mut client: Value, mut message: Value) {
        //
        //     {
        //         "id": 1583414227,
        //         "status": "ok",
        //         "subbed": "market.btcusdt.mbp.150",
        //         "ts": 1583414229143
        //     }
        //
        // unsubscribe
        //     {
        //         "id": "2",
        //         "status": "ok",
        //         "unsubbed": "market.BTC-USDT-251003.detail",
        //         "ts": 1759329276980
        //     }
        //
        let mut id: Value = self.safe_string_k(message.clone(), "id", &[]);
        let mut subscriptionsById: Value = self.index_by(get_value(&client, &Value::Str("subscriptions".to_string())), Value::Str("id".to_string()));
        let mut subscription: Value = self.safe_dict(subscriptionsById.clone(), id.clone(), &[]);
        if !is_equal(&subscription, &Value::Null) {
            let mut method: Value = self.safe_value_k(subscription.clone(), "method", &[]);
            if !is_equal(&method, &Value::Null) {
                method.call(&[client.clone(), message.clone(), subscription.clone()]);
            }
            // clean up
            if is_true(&Value::Bool(in_op(&get_value(&client, &Value::Str("subscriptions".to_string())), &id))) {
                remove(&mut get_value(&client, &Value::Str("subscriptions".to_string())), &id);
            }
        }
        if is_true(&Value::Bool(in_op(&message, &Value::Str("unsubbed".to_string())))) {
            self.handle_un_subscription(client.clone(), subscription.clone());
        }
}

    pub fn handle_un_subscription(&mut self, mut client: Value, mut subscription: Value) {
        let mut messageHashes: Value = self.safe_list_k(subscription.clone(), "messageHashes", &[Value::List(vec![])]);
        let mut subMessageHashes: Value = self.safe_list_k(subscription.clone(), "subMessageHashes", &[Value::List(vec![])]);
        {
                        let mut i: Value = Value::Int(0);
            let mut __for_first_403: bool = true;
            while { if !__for_first_403 { i = add(&i, &Value::Int(1)); } __for_first_403 = false; is_less_than(&i, &get_array_length(&messageHashes)) } {
            let mut unsubHash: Value = get_value(&messageHashes, &i);
            let mut unsubHash: Value = get_value(&messageHashes, &i);
            let mut subHash: Value = get_value(&subMessageHashes, &i);
            let mut subHash: Value = get_value(&subMessageHashes, &i);
            self.clean_unsubscription(client.clone(), subHash.clone(), unsubHash.clone(), &[]);
        }
        }
        self.clean_cache(subscription.clone());
}

